<template>
  <IosCard
    title="开场白生成工具"
    icon="fa-solid fa-comment-dots"
    icon-color="#10b981"
    hide-header
    :collapsible="false"
  >
    <!-- 说明 -->
    <div class="ios-alert ios-alert-info" style="margin-bottom: 20px">
      <i class="fa-solid fa-info-circle"></i>
      <span>根据角色卡和用户人设，AI 自动生成高质量的开场白文字。</span>
    </div>

    <!-- 当前角色信息 -->
    <div class="ios-card-inner" style="margin-bottom: 20px">
      <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 8px">
        <span class="ios-label" style="margin: 0">当前角色信息</span>
        <div class="refresh-btn" @click="refreshCharInfo">
          <i class="fa-solid fa-sync-alt"></i>
          刷新
        </div>
      </div>
      <div style="color: #fff; font-size: 14px; display: flex; align-items: center; gap: 8px">
        <i class="fa-solid fa-user" style="color: #10b981"></i>
        <span>{{ charName || '未选择角色' }}</span>
      </div>
    </div>

    <!-- 生成需求 -->
    <div style="margin-bottom: 20px">
      <label class="ios-label">生成需求</label>
      <IosTextarea
        v-model="request"
        placeholder="描述你想要的开场白场景，例如：在咖啡厅初次见面、雨天的偶遇、深夜的酒吧相遇..."
        :rows="3"
      />
    </div>

    <!-- 读取世界书开关 -->
    <div
      class="ios-card-inner"
      style="margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between"
    >
      <div>
        <div style="color: #fff; font-size: 14px; display: flex; align-items: center; gap: 8px">
          <i class="fa-solid fa-book" style="color: #10b981"></i>
          <span>结合世界书设定</span>
        </div>
        <p style="margin: 4px 0 0; color: rgba(235, 235, 245, 0.6); font-size: 11px">
          开启后会读取当前生效的全部世界书（角色卡/聊天/全局）的所有条目，让开场白更贴合世界观
        </p>
      </div>
      <label class="ios-switch">
        <input v-model="useWorldbook" type="checkbox" />
        <span class="ios-switch-slider"></span>
      </label>
    </div>

    <!-- 进度条 -->
    <div v-if="isProcessing && progress > 0" style="margin: 20px 0">
      <div class="ios-progress">
        <div class="ios-progress-bar" :style="{ width: progress + '%', background: '#10b981' }"></div>
      </div>
      <p style="text-align: center; margin-top: 8px; color: #10b981; font-size: 13px">
        生成中... {{ progress.toFixed(0) }}%
      </p>
    </div>

    <!-- 按钮 -->
    <div style="display: flex; gap: 12px; margin-bottom: 20px">
      <IosButton
        variant="primary"
        :disabled="isProcessing"
        :loading="isProcessing"
        icon="fa-solid fa-magic"
        style="background: #10b981"
        @click="handleGenerate"
      >
        {{ isProcessing ? '生成中...' : '生成开场白' }}
      </IosButton>
      <IosButton icon="fa-solid fa-trash" @click="clearForm"> 清空 </IosButton>
    </div>

    <!-- 输出区域 -->
    <div v-if="output" style="margin-top: 24px">
      <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px">
        <i class="fa-solid fa-check-circle" style="color: #10b981"></i>
        <span style="font-size: 15px; font-weight: 600; color: #fff">生成结果</span>
      </div>

      <div class="output-content">
        {{ output }}
      </div>

      <div style="margin-top: 16px; display: flex; gap: 12px">
        <IosButton icon="fa-solid fa-copy" @click="copyResult"> 复制 </IosButton>
      </div>
    </div>
  </IosCard>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { onMounted, ref, watch } from 'vue';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';
import { collectWorldbookText } from '../../utils/worldbook-reader';
import { IosButton, IosCard, IosTextarea } from '../ios';

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

const props = defineProps<{ availableWorldbooks: string[] }>();
const emit = defineEmits<{ (e: 'dataChange', data: any): void }>();

const expanded = ref(true);
const request = ref('');
const output = ref('');
const isProcessing = ref(false);
const progress = ref(0);
const charName = ref('');
const userPersona = ref('');
const useWorldbook = ref(true);

watch(
  [request, output, useWorldbook],
  () => {
    emit('dataChange', {
      request: request.value,
      output: output.value,
      useWorldbook: useWorldbook.value,
    });
  },
  { deep: true },
);

onMounted(() => {
  refreshCharInfo();
});

const refreshCharInfo = () => {
  try {
    const tav = (window as any).TavernHelper;
    if (tav?.getCharData) {
      const char = tav.getCharData('current');
      charName.value = char?.name || '';
    }
    // 尝试获取用户人设
    if (tav?.getUserPersona) {
      userPersona.value = tav.getUserPersona() || '';
    }
  } catch (e) {
    console.error('刷新角色信息失败:', e);
  }
};

const handleGenerate = async () => {
  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('正在生成开场白...');

    refreshCharInfo();

    let charInfo = '';
    const tav = (window as any).TavernHelper;
    if (tav?.getCharData) {
      const char = tav.getCharData('current');
      if (char) {
        charInfo = `【角色信息】\n角色名：${char.name || '未知'}\n`;
        const desc = char.description || char.data?.description;
        if (desc) charInfo += `描述：${desc}\n`;
        const personality = char.personality || char.data?.personality;
        if (personality) charInfo += `性格：${personality}\n`;
        const scenario = char.scenario || char.data?.scenario;
        if (scenario) charInfo += `场景：${scenario}\n`;
      }
    }

    // 读取当前生效的全部世界书（全部条目），让开场白更贴合世界观
    let worldbookInfo = '';
    if (useWorldbook.value) {
      try {
        const wbText = await collectWorldbookText({ maxLength: 8000 });
        if (wbText) {
          worldbookInfo = `\n【世界书设定（当前生效的全部世界书条目）】\n${wbText}\n`;
        } else {
          window.toastr.info('未读取到可用的世界书内容，将仅依据角色卡生成');
        }
      } catch (e) {
        console.warn('读取世界书失败:', e);
      }
    }

    const systemPrompt = `你是一个专业的角色扮演开场白作家。请基于提供的角色信息和用户需求，生成一段高质量、沉浸感强的开场白文字。

要求：
1. 符合角色性格和设定
2. 营造氛围，吸引用户进入故事
3. 可以包含角色的动作、神态、对话
4. 使用第三人称视角描写角色
5. 长度适中，约 200-500 字
6. 避免八股和套话，用自然的文风

${charInfo}
${userPersona.value ? `【用户人设】\n${userPersona.value}\n` : ''}${worldbookInfo}`;

    const messages = [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: request.value || '请生成一段符合角色设定的开场白' },
    ];

    output.value = await callAIWithTavernSupport(
      messages,
      {
        ...settings.value,
      },
      {
        onProgress: (p: number) => (progress.value = p),
      },
    );

    window.toastr.success('开场白生成完成！');
  } catch (error) {
    console.error('开场白生成失败:', error);
    window.toastr.error(translateError(error, '生成'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

const copyResult = () => {
  if (!output.value) return;
  copyToClipboard(output.value, '开场白已复制');
};

const clearForm = () => {
  request.value = '';
  output.value = '';
};

defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      request.value = data.request || '';
      output.value = data.output || '';
      if (typeof data.useWorldbook === 'boolean') useWorldbook.value = data.useWorldbook;
    }
  },
});
</script>

